const MusicPlayer=(()=>{"use strict";const TRACKS=[{src:"music/coastline.mp3",title:"Hollow Coves - Coastline",sectionStart:0,sectionEnd:.33}];const FADE_DURATION_MS=1500;const FADE_INTERVAL_MS=50;const MAX_VOLUME=.6;let audioElement=null;let currentTrackIndex=-1;let isMuted=false;let isPlaying=false;let hasUserInteracted=false;let shuffledOrder=[];let shufflePosition=0;let fadeInterval=null;let muteButton=null;let trackInfoElement=null;function generateShuffledOrder(){const indices=TRACKS.map((_,i)=>i);const seed=(new Date).toDateString();let seedHash=0;for(let i=0;i<seed.length;i++){seedHash=(seedHash<<5)-seedHash+seed.charCodeAt(i);seedHash=seedHash&seedHash}let rng=Math.abs(seedHash);for(let i=indices.length-1;i>0;i--){rng=(rng*16807+0)%2147483647;const j=rng%(i+1);[indices[i],indices[j]]=[indices[j],indices[i]]}return indices}function ensureAudioElement(){if(!audioElement){audioElement=new Audio;audioElement.loop=true;audioElement.volume=0;audioElement.muted=isMuted;audioElement.preload="auto";audioElement.addEventListener("ended",()=>{playNextTrack()});audioElement.addEventListener("error",e=>{console.warn("Music player: failed to load track",TRACKS[currentTrackIndex]?.src,e);playNextTrack()})}}function fadeVolumeTo(targetVolume,onComplete){if(fadeInterval)clearInterval(fadeInterval);if(!audioElement){if(onComplete)onComplete();return}if(isMuted){audioElement.muted=true;audioElement.volume=0;if(onComplete)onComplete();return}audioElement.muted=false;const startVolume=audioElement.volume;const steps=FADE_DURATION_MS/FADE_INTERVAL_MS;const volumeStep=(targetVolume-startVolume)/steps;let currentStep=0;fadeInterval=setInterval(()=>{currentStep++;const newVolume=startVolume+volumeStep*currentStep;audioElement.volume=Math.max(0,Math.min(1,newVolume));if(currentStep>=steps){clearInterval(fadeInterval);fadeInterval=null;audioElement.volume=Math.max(0,Math.min(1,targetVolume));if(onComplete)onComplete()}},FADE_INTERVAL_MS)}function loadAndPlayTrack(trackIndex){if(trackIndex<0||trackIndex>=TRACKS.length)return;if(trackIndex===currentTrackIndex&&isPlaying)return;ensureAudioElement();const track=TRACKS[trackIndex];const wasPlaying=isPlaying;const startPlay=()=>{currentTrackIndex=trackIndex;audioElement.src=track.src;audioElement.muted=isMuted;audioElement.play().then(()=>{isPlaying=true;fadeVolumeTo(isMuted?0:MAX_VOLUME);updateTrackInfo()}).catch(err=>{console.warn("Music player: autoplay blocked or error",err);isPlaying=false})};if(wasPlaying&&currentTrackIndex!==trackIndex){fadeVolumeTo(0,startPlay)}else{startPlay()}}function playNextTrack(){if(shuffledOrder.length===0){shuffledOrder=generateShuffledOrder();shufflePosition=0}shufflePosition=(shufflePosition+1)%shuffledOrder.length;loadAndPlayTrack(shuffledOrder[shufflePosition])}function getScrollProgress(){const scrollTop=window.scrollY||document.documentElement.scrollTop;const docHeight=document.documentElement.scrollHeight-window.innerHeight;if(docHeight<=0)return 0;return Math.max(0,Math.min(1,scrollTop/docHeight))}function getTrackForScrollPosition(){const progress=getScrollProgress();for(let i=0;i<TRACKS.length;i++){if(progress>=TRACKS[i].sectionStart&&progress<TRACKS[i].sectionEnd)return i}return-1}function handleScroll(){if(!hasUserInteracted)return;if(!isPlaying&&getScrollProgress()>.01){const idx=getTrackForScrollPosition();loadAndPlayTrack(idx>=0?idx:shuffledOrder[shufflePosition]||0);return}const target=getTrackForScrollPosition();if(target>=0&&target!==currentTrackIndex)loadAndPlayTrack(target)}function createMuteButton(){muteButton=document.createElement("button");muteButton.id="musicToggle";muteButton.setAttribute("aria-label","Toggle music");muteButton.innerHTML="▶️";Object.assign(muteButton.style,{position:"fixed",bottom:"30px",left:"30px",zIndex:"1000",width:"50px",height:"50px",borderRadius:"50%",border:"1px solid rgba(255,255,255,0.10)",background:"rgba(255,255,255,0.05)",backdropFilter:"blur(20px)",WebkitBackdropFilter:"blur(20px)",color:"rgba(255,255,255,0.92)",fontSize:"1.3em",cursor:"pointer",transition:"all 0.3s ease",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 18px 60px rgba(0,0,0,0.55)"});muteButton.addEventListener("mouseenter",()=>{muteButton.style.background="rgba(255,255,255,0.10)";muteButton.style.transform="translateY(-2px)"});muteButton.addEventListener("mouseleave",()=>{muteButton.style.background="rgba(255,255,255,0.05)";muteButton.style.transform="translateY(0)"});muteButton.addEventListener("click",toggleMute);document.body.appendChild(muteButton);trackInfoElement=document.createElement("div");trackInfoElement.id="trackInfo";Object.assign(trackInfoElement.style,{position:"fixed",bottom:"90px",left:"30px",zIndex:"1000",padding:"8px 16px",borderRadius:"12px",border:"1px solid rgba(255,255,255,0.10)",background:"rgba(255,255,255,0.05)",backdropFilter:"blur(20px)",WebkitBackdropFilter:"blur(20px)",color:"rgba(255,255,255,0.62)",fontFamily:"Inter,-apple-system,sans-serif",fontSize:"0.8em",letterSpacing:"0.02em",opacity:"0",transition:"opacity 0.5s ease",pointerEvents:"none"});document.body.appendChild(trackInfoElement)}function toggleMute(){hasUserInteracted=true;if(!isPlaying){isMuted=false;localStorage.setItem("musicMuted","false");if(audioElement)audioElement.muted=false;if(muteButton)muteButton.innerHTML="🔊";const idx=getTrackForScrollPosition();loadAndPlayTrack(idx>=0?idx:shuffledOrder[0]||0);return}isMuted=!isMuted;localStorage.setItem("musicMuted",isMuted?"true":"false");if(muteButton)muteButton.innerHTML=isMuted?"🔇":"🔊";if(audioElement){if(isMuted){audioElement.muted=true;fadeVolumeTo(0)}else{audioElement.muted=false;fadeVolumeTo(MAX_VOLUME)}}}function updateTrackInfo(){if(!trackInfoElement||currentTrackIndex<0)return;trackInfoElement.textContent="♪ "+TRACKS[currentTrackIndex].title;trackInfoElement.style.opacity="1";setTimeout(()=>{if(trackInfoElement)trackInfoElement.style.opacity="0"},3e3)}function init(){isMuted=localStorage.getItem("musicMuted")==="true";shuffledOrder=generateShuffledOrder();shufflePosition=0;createMuteButton();ensureAudioElement();let scrollTimeout=null;window.addEventListener("scroll",()=>{if(scrollTimeout)clearTimeout(scrollTimeout);scrollTimeout=setTimeout(handleScroll,150)},{passive:true});const events=["click","touchstart","keydown"];const onFirst=()=>{hasUserInteracted=true;events.forEach(e=>document.removeEventListener(e,onFirst));if(!isPlaying&&!isMuted){const idx=getTrackForScrollPosition();loadAndPlayTrack(idx>=0?idx:shuffledOrder[0]||0)}};events.forEach(e=>document.addEventListener(e,onFirst,{once:false}))}return{init:init,toggleMute:toggleMute,setTracks(t){TRACKS.length=0;TRACKS.push(...t);shuffledOrder=generateShuffledOrder();shufflePosition=0}}})();if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",MusicPlayer.init)}else{MusicPlayer.init()}